    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         data: {
        //             E: '1754601477746429',
        //             T: '1754601477744000',
        //             a: '5121860761',
        //             b: '5121861755',
        //             e: 'trade',
        //             m: false,
        //             p: '3870.25',
        //             q: '0.0008',
        //             s: 'ETH_USDC_PERP',
        //             t: 10782547
        //         },
        //         stream: 'trade.ETH_USDC_PERP'
        //     }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(data, "s");
        Object market = this.market(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        if (!Helpers.isTrue((Helpers.inOp(this.trades, symbol))))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            var stored = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, stored);
        }
        Object cache = Helpers.GetValue(this.trades, symbol);
        Object trade = this.parseWsTrade(data, market);
        Helpers.callDynamically(cache, "append", new Object[]{trade});
        Object messageHash = Helpers.add("trades:", symbol);
        client.resolve(cache, messageHash);
        client.resolve(cache, "trades");
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        //     {
        //         E: '1754601477746429',
        //         T: '1754601477744000',
        //         a: '5121860761',
        //         b: '5121861755',
        //         e: 'trade',
        //         m: false,
        //         p: '3870.25',
        //         q: '0.0008',
        //         s: 'ETH_USDC_PERP',
        //         t: 10782547
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object microseconds = this.safeInteger(trade, "E");
        Object timestamp = this.parseToInt(Helpers.divide(microseconds, 1000));
        Object id = this.safeString(trade, "t");
        Object marketId = this.safeString(trade, "s");
        market = this.safeMarket(marketId, market);
        Object isBuyerMaker = this.safeBool(trade, "m");
        Object side = null;
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isBuyerMaker, null)))
        {
            takerOrMaker = "taker";
            if (Helpers.isTrue(isBuyerMaker))
            {
                side = "sell";
            } else
            {
                side = "buy";
            }
        }
        Object price = this.safeString(trade, "p");
        Object amount = this.safeString(trade, "q");
        Object orderId = null;
        if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
        {
            orderId = this.safeString(trade, "b");
        } else
        {
            orderId = this.safeString(trade, "a");
        }
        final Object finalMarket = market;
        final Object finalOrderId = orderId;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", BackpackCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", finalOrderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", null );
                put( "cost", null );
            }} );
        }}, market);
    }

